export const SUPPORT_SERVER_URL = "https://discord.gg/example";

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getBotResponse = async (userMessage: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: userMessage,
      config: {
        systemInstruction: `You are the AI personality for "Nexus", a Discord bot. 
        You are helpful, modern, slightly witty, and tech-savvy. 
        You use Discord emojis like :rocket:, :sparkles:, and :link: in your speech. 
        Your main features include advanced moderation, utility commands, and AI-powered chat.
        Encourage the user to add you to their server using the invite link.
        Keep responses concise (under 200 words).`,
        temperature: 0.8,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Oops! My circuits got a bit tangled. Can you try asking me that again? :tools:";
  }
};

