import { GoogleGenAI } from "@google/genai";
import { BOT_NAME } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getBotResponse = async (userMessage: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: userMessage,
      config: {
        systemInstruction: `You are the simulated AI personality for "${BOT_NAME}", acting inside a Discord UI mockup that ACTUALLY plays music.
        The user is interacting with you via Discord commands or general chat.

        If the user uses a command (starts with /):
        - /play [song]: Act excited. Mention that you've fetched a high-quality track for them. Confirm that audio should be audible now.
        - /skip: Confirm the skip to the next track in the demo library.
        - /stop: Confirm you've stopped the music stream.
        - /help: List your main features: Real-time high-fidelity music, interactive games, and 24/7 reliability.

        CRITICAL: The UI will actually start playing audio when they type /play. Your job is to narrate this experience.

        Style:
        - Use Discord markdown (**bold**, \`code\`, > quotes).
        - Use emojis: :notes:, :musical_note:, :white_check_mark:, :speaker:.
        - Be friendly, professional, and slightly "gamer" oriented.
        - Keep responses concise (under 80 words).`,
        temperature: 0.8,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "**:warning: Error:** Lost connection to the music gateway. Please try `/play` again! :tools:";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { getBotResponse } from '../services/geminiService';
import { BOT_NAME } from '../constants';
import MusicIcon from './MusicIcon';

interface Message {
  author: string;
  avatar: string;
  text: string;
  isBot: boolean;
  timestamp: string;
  isEmbed?: boolean;
}

const NCS_TRACKS = [
  { title: "NCS: Alan Walker - Fade (Electronic)", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3", duration: 372 },
  { title: "NCS: Deaf Kev - Invincible (House)", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3", duration: 425 },
  { title: "NCS: Cartoon - On & On (Future Bass)", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3", duration: 316 },
  { title: "NCS: Janji - Heroes Tonight (Progressive)", url: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-4.mp3", duration: 288 }
];

const InteractiveAI: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { 
      author: BOT_NAME, 
      avatar: 'bot',
      text: `Welcome to the **${BOT_NAME}** preview! I'm ready to play some NCS hits. :rocket: \n\nTry these commands:\n> \`/tpg play\` - Play a random NCS track\n> \`/tpg skip\` - Skip to the next banger\n> \`/tpg stop\` - Stop the music and leave`, 
      isBot: true,
      timestamp: 'Today at 12:00 PM'
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [nowPlaying, setNowPlaying] = useState<typeof NCS_TRACKS[0] | null>(null);
  const [playbackTime, setPlaybackTime] = useState(0);
  const [isPaused, setIsPaused] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const progressInterval = useRef<number | null>(null);

  useEffect(() => {
    audioRef.current = new Audio();
    audioRef.current.volume = 0.5;

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
      if (progressInterval.current) clearInterval(progressInterval.current);
    };
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const startProgressTracking = () => {
    if (progressInterval.current) clearInterval(progressInterval.current);
    progressInterval.current = window.setInterval(() => {
      if (audioRef.current && !audioRef.current.paused) {
        setPlaybackTime(audioRef.current.currentTime);
      }
    }, 1000);
  };

  const handlePlayMusic = (trackIndex: number = 0) => {
    const track = NCS_TRACKS[trackIndex];
    if (audioRef.current) {
      audioRef.current.src = track.url;
      audioRef.current.play().catch(e => {
        console.warn("Autoplay blocked, user interaction required first.", e);
      });
      setNowPlaying(track);
      setPlaybackTime(0);
      setIsPaused(false);
      startProgressTracking();
    }
  };

  const handleStopMusic = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
    }
    setNowPlaying(null);
    setPlaybackTime(0);
    if (progressInterval.current) clearInterval(progressInterval.current);
  };

  const togglePause = () => {
    if (audioRef.current) {
      if (audioRef.current.paused) {
        audioRef.current.play();
        setIsPaused(false);
      } else {
        audioRef.current.pause();
        setIsPaused(true);
      }
    }
  };

  const getCurrentTime = () => {
    const now = new Date();
    return `Today at ${now.getHours() % 12 || 12}:${now.getMinutes().toString().padStart(2, '0')} ${now.getHours() >= 12 ? 'PM' : 'AM'}`;
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userText = input.trim();
    setInput('');

    setMessages(prev => [...prev, { 
      author: 'You', 
      avatar: 'user',
      text: userText, 
      isBot: false,
      timestamp: getCurrentTime()
    }]);

    setIsTyping(true);

    // Command Logic with /tpg prefix
    const lowerText = userText.toLowerCase();
    let botPrefix = "";

    if (lowerText.startsWith('/tpg play')) {
      const trackIdx = Math.floor(Math.random() * NCS_TRACKS.length);
      handlePlayMusic(trackIdx);
      botPrefix = `**:musical_note: Now playing:** \`${NCS_TRACKS[trackIdx].title}\` [NCS Release] :fire:\n\n`;
    } else if (lowerText.startsWith('/tpg stop') || lowerText.startsWith('/tpg leave')) {
      handleStopMusic();
      botPrefix = `**:white_check_mark: Music stopped.** The stage is quiet now. \n\n`;
    } else if (lowerText.startsWith('/tpg skip')) {
       const trackIdx = Math.floor(Math.random() * NCS_TRACKS.length);
       handlePlayMusic(trackIdx);
       botPrefix = `**:track_next: Skipped!** Next NCS hit: \`${NCS_TRACKS[trackIdx].title}\` \n\n`;
    }

    const botText = await getBotResponse(userText);
    setIsTyping(false);

    setMessages(prev => [...prev, { 
      author: BOT_NAME, 
      avatar: 'bot',
      text: botPrefix + (botText || "Processed command."), 
      isBot: true,
      timestamp: getCurrentTime(),
      isEmbed: userText.startsWith('/tpg')
    }]);
  };

  return (
    <section id="ai-demo" className="px-4 md:px-6 py-24 relative overflow-hidden bg-[#020617]">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-12">
          <div className="inline-block px-3 py-1 rounded-full bg-indigo-500/20 border border-indigo-500/30 text-indigo-400 text-[10px] font-bold uppercase tracking-wider mb-4">
            Bot Preview
          </div>
          <h2 className="text-3xl md:text-5xl font-black mb-4">Live NCS Player</h2>
          <p className="text-gray-400 text-lg">Use the <code className="text-pink-400">/tpg</code> prefix to control the bot below.</p>
        </div>

        <div className="relative group max-w-5xl mx-auto">
          <div className="flex h-[600px] bg-[#313338] rounded-2xl overflow-hidden shadow-2xl border border-white/5 ring-1 ring-black/50">

            {/* Server Sidebar */}
            <div className="hidden sm:flex flex-col w-[72px] bg-[#1e1f22] items-center py-3 gap-2 border-r border-black/20">
              <div className="w-12 h-12 rounded-[50%] hover:rounded-[15px] transition-all duration-200 bg-[#313338] flex items-center justify-center group/icon cursor-pointer">
                <MusicIcon size="sm" className="!bg-transparent !shadow-none !ring-0 !w-8 !h-8" />
              </div>
              <div className="w-8 h-[2px] bg-[#35363c] rounded-full mx-auto my-1"></div>
              <div className="w-12 h-12 rounded-[15px] bg-[#5865f2] flex items-center justify-center cursor-default">
                <span className="text-white font-bold">TPG</span>
              </div>
            </div>

            {/* Channel Sidebar */}
            <div className="hidden md:flex flex-col w-60 bg-[#2b2d31]">
               <div className="h-12 px-4 flex items-center shadow-sm border-b border-black/10 font-bold text-white">
                 ─・𒀛TPG ｜MUSIC
               </div>
               <div className="p-3 space-y-4">
                 <div className="space-y-1">
                   <div className="text-[11px] font-bold text-gray-400 uppercase px-2 mb-1">Text Channels</div>
                   <div className="flex items-center gap-2 px-2 py-1 rounded bg-[#3f4147] text-white cursor-pointer group">
                     <span className="text-gray-400 group-hover:text-white transition-colors">#</span>
                     <span className="text-sm font-medium">general</span>
                   </div>
                 </div>
                 <div className="space-y-1">
                   <div className="text-[11px] font-bold text-gray-400 uppercase px-2 mb-1">Voice Channels</div>
                   <div className="flex items-center gap-2 px-2 py-1 rounded hover:bg-[#35373c] text-green-400 cursor-pointer group">
                     <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M12 3v10.55c-.59-.34-1.27-.55-2-.55-2.21 0-4 1.79-4 4s1.79 4 4 4 4-1.79 4-4V7h4V3h-6z"/></svg>
