import React, { useRef } from 'react';
import { motion, useMotionValue, useSpring, useTransform } from 'framer-motion';

const FeatureCard = ({ title, description, icon, color }: { title: string, description: string, icon: string, color: string }) => {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x);
  const mouseYSpring = useSpring(y);

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["10deg", "-10deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-10deg", "10deg"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const xPct = mouseX / width - 0.5;
    const yPct = mouseY / height - 0.5;
    x.set(xPct);
    y.set(yPct);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <motion.div
      style={{ rotateX, rotateY, transformStyle: "preserve-3d" }}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      className="relative h-96 w-full rounded-[32px] glass-panel border border-white/5 p-8 flex flex-col justify-end group cursor-default"
    >
      <div 
        className="absolute top-8 right-8 text-5xl transition-transform duration-500 group-hover:scale-125"
        style={{ transform: "translateZ(50px)" }}
      >
        {icon}
      </div>

      <div 
        className="relative z-10"
        style={{ transform: "translateZ(30px)" }}
      >
        <div className={`w-8 h-8 rounded-full mb-6 bg-gradient-to-br ${color} blur-xl group-hover:scale-150 transition-transform`}></div>
        <h3 className="text-2xl font-black mb-3 text-white">{title}</h3>
        <p className="text-gray-500 text-sm leading-relaxed max-w-[250px]">{description}</p>
      </div>

      <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity rounded-[32px]"></div>
    </motion.div>
  );
};

