          {[
            { label: "Active Servers", value: servers, icon: "SVR", color: "from-indigo-500 to-blue-500" },
            { label: "Verified Users", value: users, icon: "USR", color: "from-white to-gray-500" },
            { label: "Global Uptime", value: "99.99", icon: "UPT", color: "from-emerald-500 to-teal-500", suffix: "%" },
            { label: "API Latency", value: "14", icon: "LAT", color: "from-rose-500 to-orange-500", suffix: "ms" }
          ].map((stat, i) => (
            <motion.div 
              key={i}
