              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.1, duration: 0.8 }}
              whileHover={{ y: -10, rotateX: -5, rotateY: 5 }}
              className="glass-panel rounded-[2rem] p-12 border border-white/5 relative overflow-hidden group transition-all"
              style={{ transformStyle: 'preserve-3d', perspective: '1000px' }}
            >
              <div className="absolute top-0 right-0 p-4 font-mono text-[8px] text-gray-800 tracking-widest font-black uppercase opacity-20 group-hover:opacity-40 transition-opacity">
                {stat.icon} // 0{i + 1}
              </div>

              <div 
                className={`text-5xl md:text-6xl font-black mb-6 bg-clip-text text-transparent bg-gradient-to-br ${stat.color} tracking-tighter`}
                style={{ transform: 'translateZ(40px)' }}
              >
                {typeof stat.value === 'number' ? <CountUp value={stat.value} /> : stat.value}
                {stat.suffix && <span className="text-xl md:text-2xl ml-1">{stat.suffix}</span>}
