import React from 'react';
import { motion, useMotionValue, useSpring, useTransform } from 'framer-motion';

const FeatureCard = ({ title, description, icon, color }: { title: string, description: string, icon: string, color: string }) => {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x, { stiffness: 300, damping: 30 });
  const mouseYSpring = useSpring(y, { stiffness: 300, damping: 30 });

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["15deg", "-15deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-15deg", "15deg"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const xPct = mouseX / width - 0.5;
    const yPct = mouseY / height - 0.5;
    x.set(xPct);
    y.set(yPct);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <motion.div
      style={{ rotateX, rotateY, transformStyle: "preserve-3d" }}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      className="relative h-[450px] w-full rounded-[40px] glass-panel border border-white/5 p-12 flex flex-col justify-end group cursor-default overflow-hidden"
    >
      <div 
        className="absolute top-12 right-12 text-7xl transition-transform duration-700 group-hover:scale-125 group-hover:rotate-12 opacity-80"
        style={{ transform: "translateZ(80px)" }}
      >
        {icon}
      </div>

      <div 
        className="relative z-10"
        style={{ transform: "translateZ(50px)" }}
      >
        <div className={`w-12 h-1 rounded-full mb-8 bg-gradient-to-r ${color} shadow-[0_0_20px_rgba(255,255,255,0.2)]`}></div>
        <h3 className="text-3xl font-black mb-4 text-white tracking-tighter uppercase">{title}</h3>
        <p className="text-gray-500 text-sm leading-relaxed max-w-[280px] font-medium tracking-wide">{description}</p>
      </div>

      <div className="absolute inset-0 bg-gradient-to-br from-white/10 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
    </motion.div>
  );
};

