  user?: any;
}

const InteractiveAI: React.FC<InteractiveAIProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isBooting, setIsBooting] = useState(true);
  const [bootText, setBootText] = useState('');
  const [nowPlaying, setNowPlaying] = useState<Track | null>(null);
  const [isLooping, setIsLooping] = useState(false);
  const [volume, setVolume] = useState(50);

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const bootSequence = [
    "TPG_MUSIC CORE v5.2.0-STABLE",
    "AUDIO_ENGINE: INITIALIZING NCS_PROTOCOLS",
    "NODE_SYNC: ATTACHED (8ms)",
    "AUTH_GATEWAY: VERIFIED",
    "BUFFER_CALIBRATION: [OK]",
    "REALTIME_SSL: ESTABLISHED",
    "SYSTEM READY."
  ];

  useEffect(() => {
    audioRef.current = new Audio();
    audioRef.current.volume = volume / 100;

    let currentLine = 0;
    const bootInterval = setInterval(() => {
      if (currentLine < bootSequence.length) {
        setBootText(prev => prev + (prev ? '\n' : '') + '> ' + bootSequence[currentLine]);
        currentLine++;
      } else {
        clearInterval(bootInterval);
        setTimeout(() => {
          setIsBooting(false);
          setMessages([
            { 
              author: BOT_NAME, 
              avatar: 'bot', 
              text: `Core active. System initialized. I am ready to play NCS high-fidelity tracks. Use \`/tpg play\` to begin.`, 
              isBot: true, 
              timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
            }
          ]);
        }, 500);
      }
    }, 80);
    return () => {
      clearInterval(bootInterval);
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume / 100;
    }
  }, [volume]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.loop = isLooping;
    }
  }, [isLooping]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isTyping, bootText]);

  const addBotMessage = (text: string) => {
    const now = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    setMessages(prev => [...prev, { author: BOT_NAME, avatar: 'bot', text, isBot: true, timestamp: now }]);
  };

  const processCommand = async (cmd: string) => {
    const lower = cmd.toLowerCase().trim();
    const args = lower.split(' ').slice(1);
    const subCommand = lower.startsWith('/') ? lower.split(' ')[0] : null;
    const fullCmd = lower.startsWith('/tpg ') ? lower.split(' ')[1] : (subCommand ? subCommand.replace('/', '') : null);

    if (lower === '/tpg support') {
      addBotMessage(`💠 **SUPPORT SYSTEM**\nDirect Link: ${SUPPORT_SERVER_URL}\nDeployment specialists are standing by.`);
      return true;
    }

    if (lower.startsWith('/tpg play') || lower.startsWith('/play')) {
      const search = args.join(' ');
      let track = NCS_SONGS.find(s => s.title.toLowerCase().includes(search) || s.artist.toLowerCase().includes(search));
      if (!track) track = NCS_SONGS[Math.floor(Math.random() * NCS_SONGS.length)];

      setNowPlaying(track);
      if (audioRef.current) {
        audioRef.current.src = track.url;
        audioRef.current.play().catch(e => console.error("Playback failed:", e));
      }
      addBotMessage(`💠 **STREAMING INITIALIZED**\n\`\`\`yaml\nTRACK: ${track.title}\nARTIST: ${track.artist}\nSTATUS: PLAYING\nQUALITY: LOSSLESS (1411kbps)\n\`\`\``);
      return true;
    }

    if (lower === '/tpg stop' || lower === '/stop') {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.currentTime = 0;
      }
      setNowPlaying(null);
      addBotMessage(`⏹️ **SESSION TERMINATED**\nPlayback stack cleared. Node idle.`);
      return true;
    }

    if (lower === '/tpg pause' || lower === '/pause') {
      audioRef.current?.pause();
      addBotMessage(`⏸️ **STREAM SUSPENDED**\nAudio buffer preserved.`);
      return true;
    }

    if (lower === '/tpg resume' || lower === '/resume') {
      audioRef.current?.play();
      addBotMessage(`▶️ **STREAM RESTORED**\nSynchronizing audio packets...`);
      return true;
    }

    if (lower === '/tpg loop' || lower === '/loop') {
      setIsLooping(!isLooping);
      addBotMessage(`🔄 **LOOP MODE: ${!isLooping ? 'ENABLED' : 'DISABLED'}**`);
      return true;
    }

    if (lower === '/tpg queue' || lower === '/queue') {
      const queueList = NCS_SONGS.map((s, i) => `${i + 1}. ${s.title} - ${s.artist}`).join('\n');
      addBotMessage(`📜 **CURRENT STACK**\n\`\`\`\n${queueList}\n\`\`\``);
      return true;
