      audioRef.current?.pause();
      setNowPlaying(null);
      addBotMessage(`🔌 **NODE DECOUPLED**\nConnection closed.`);
      return true;
    }

    if (lower === '/tpg replay' || lower === '/replay') {
      if (audioRef.current) audioRef.current.currentTime = 0;
      audioRef.current?.play();
      addBotMessage(`⏪ **REPLAYING TRACK**`);
      return true;
    }

    if (lower === '/tpg skip' || lower === '/skip') {
      const next = NCS_SONGS[Math.floor(Math.random() * NCS_SONGS.length)];
