      }
      addBotMessage(`⏭️ **SKIPPED**\nNow playing: **${next.title}**`);
      return true;
    }

    if (lower === '/tpg track' || lower === '/track') {
      if (!nowPlaying) {
        addBotMessage(`❌ **NO TRACK ACTIVE**`);
      } else {
        addBotMessage(`🎵 **TRACK METADATA**\nTitle: ${nowPlaying.title}\nArtist: ${nowPlaying.artist}\nCodec: FLAC/PCM`);
      }
      return true;
    }

    if (lower.startsWith('/tpg set-volume') || lower.startsWith('/volume')) {
      const vol = parseInt(args[0] || args[1]);
      if (!isNaN(vol) && vol >= 0 && vol <= 100) {
        setVolume(vol);
        addBotMessage(`🔊 **VOLUME CALIBRATED: ${vol}%**`);
      } else {
        addBotMessage(`❌ **INVALID INPUT**\nUsage: /tpg set-volume [0-100]`);
      }
      return true;
    }

    return false;
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping || isBooting) return;

    const userText = input.trim();
    setInput('');
    const now = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    const userAvatar = user?.avatar || "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?q=80&w=1000&auto=format&fit=crop";

    setMessages(prev => [...prev, { author: user?.username || 'OPERATOR', avatar: userAvatar, text: userText, isBot: false, timestamp: now }]);
    setIsTyping(true);

    const wasCommand = await processCommand(userText);
    if (wasCommand) {
      setIsTyping(false);
      return;
    }

    const botText = await getBotResponse(userText);
    setIsTyping(false);
    addBotMessage(botText || "Connection unstable. Retrying...");
  };

  return (
